 35→
 36→/// Docker/Podman-based sandbox implementation.
 37→///
 38→/// The `cli` field selects the container CLI binary (`"docker"` or `"podman"`).
 39→/// Podman's CLI is a drop-in replacement for Docker, so both backends share
 40→/// this single implementation.
 41→pub struct DockerSandbox {
 42→    pub config: SandboxConfig,
 43→    cli: &'static str,
 44→    backend_label: &'static str,
 45→}
 46→
 47→impl DockerSandbox {
 48→    pub fn new(config: SandboxConfig) -> Self {
 49→        Self {
 50→            config,
 51→            cli: "docker",
 52→            backend_label: "docker",
 53→        }
 54→    }
 55→
 56→    pub fn podman(config: SandboxConfig) -> Self {
 57→        Self {
 58→            config,
 59→            cli: "podman",
 60→            backend_label: "podman",
 61→        }
 62→    }
 63→
 64→    fn image(&self) -> &str {
 65→        self.config
 66→            .image
 67→            .as_deref()
 68→            .unwrap_or(DEFAULT_SANDBOX_IMAGE)
 69→    }
 70→
 71→    fn container_prefix(&self) -> &str {
 72→        self.config
 73→            .container_prefix
 74→            .as_deref()
 75→            .unwrap_or("moltis-sandbox")
 76→    }
 77→
 78→    pub(crate) fn container_name(&self, id: &SandboxId) -> String {
 79→        format!("{}-{}", self.container_prefix(), id.key)
 80→    }
 81→
 82→    fn image_repo(&self) -> &str {
 83→        self.container_prefix()
 84→    }
 85→
 86→    fn mounted_host_path(&self, id: &SandboxId, guest_path: &str) -> Option<std::path::PathBuf> {
 87→        let guest_path = std::path::Path::new(guest_path);
 88→        resolve_workspace_guest_path_on_host(&self.config, Some(self.cli), guest_path).or_else(
 89→            || {
 90→                resolve_home_persistence_guest_path_on_host(
 91→                    &self.config,
 92→                    Some(self.cli),
 93→                    id,
 94→                    guest_path,
 95→                )
 96→            },
 97→        )
 98→    }
 99→
100→    pub(crate) fn resource_args(&self) -> Vec<String> {
101→        let mut args = Vec::new();
102→        let limits = &self.config.resource_limits;
103→        if let Some(ref mem) = limits.memory_limit {
104→            args.extend(["--memory".to_string(), mem.clone()]);
105→        }
106→        if let Some(cpu) = limits.cpu_quota {
107→            args.extend(["--cpus".to_string(), cpu.to_string()]);
108→        }
109→        if let Some(pids) = limits.pids_max {
110→            args.extend(["--pids-limit".to_string(), pids.to_string()]);
111→        }
112→        args
113→    }
114→
115→    pub(crate) fn network_run_args(&self) -> Vec<String> {
116→        match self.config.network {
117→            NetworkPolicy::Blocked => vec!["--network=none".to_string()],
118→            NetworkPolicy::Trusted => {
119→                // Ensure the container can reach the host proxy on all
120→                // platforms (Linux needs --add-host; macOS Docker Desktop
121→                // resolves host.docker.internal automatically).
122→                let gateway = self.resolve_host_gateway();
123→                vec![format!("--add-host=host.docker.internal:{gateway}")]
124→            },
125→            NetworkPolicy::Bypass => Vec::new(),
126→        }
127→    }
128→
129→    /// Resolve the IP that containers use to reach the host.
130→    ///
131→    /// Docker (and Podman >= 5.0) support the special `host-gateway` token in
132→    /// `--add-host`.  Older Podman versions reject it with:
133→    ///
134→    ///   Error: invalid IP address in add-host: "host-gateway"
135→    ///
136→    /// For those we resolve the address ourselves: rootless Podman (< 5.0) uses
137→    /// slirp4netns by default, which maps the host to `10.0.2.2`.  Rootful
138→    /// Podman uses a bridge whose gateway we can query via
139→    /// `podman network inspect`.
140→    pub(crate) fn resolve_host_gateway(&self) -> String {
141→        if self.cli != "podman" {
142→            return "host-gateway".to_string();
143→        }
144→
145→        if podman_supports_host_gateway() {
146→            return "host-gateway".to_string();
147→        }
148→
149→        // Podman < 5.0 — resolve the address manually.
150→        podman_resolve_host_ip().unwrap_or_else(|| {
151→            debug!(
152→                "could not resolve host gateway IP for podman; \
153→                 falling back to host-gateway (may fail)"
154→            );
155→            "host-gateway".to_string()
156→        })
157→    }
158→
159→    pub(crate) fn proxy_exec_env_args(&self) -> Vec<String> {
160→        if self.config.network != NetworkPolicy::Trusted {
161→            return Vec::new();
162→        }
163→        let proxy_url = format!(
164→            "http://host.docker.internal:{}",
165→            moltis_network_filter::DEFAULT_PROXY_PORT
166→        );
167→        let mut args = Vec::new();
168→        for key in ["HTTP_PROXY", "http_proxy", "HTTPS_PROXY", "https_proxy"] {
169→            args.extend(["-e".to_string(), format!("{key}={proxy_url}")]);
170→        }
171→        for key in ["NO_PROXY", "no_proxy"] {
172→            args.extend(["-e".to_string(), format!("{key}=localhost,127.0.0.1,::1")]);
173→        }
174→        args
175→    }
176→
177→    /// Security hardening flags for `docker run`.
178→    ///
179→    /// `is_prebuilt` controls whether `--read-only` is applied: prebuilt images
180→    /// already have packages baked in so the root FS can be read-only, while
181→    /// non-prebuilt images need a writable root for `apt-get` provisioning.
182→    pub(crate) fn hardening_args(is_prebuilt: bool) -> Vec<String> {
183→        let mut args = vec![
184→            // --- Capability / privilege ---
185→            "--cap-drop".to_string(),
186→            "ALL".to_string(),
187→            "--security-opt".to_string(),
188→            "no-new-privileges".to_string(),
189→            // --- Writable tmpfs mounts ---
190→            "--tmpfs".to_string(),
191→            "/tmp:rw,nosuid,size=256m".to_string(),
192→            "--tmpfs".to_string(),
193→            "/run:rw,nosuid,size=64m".to_string(),
194→            // --- Host metadata isolation ---
195→            // Give the container its own hostname so /proc/sys/kernel/hostname
196→            // and the `hostname` command do not reveal the host identity.
197→            "--hostname".to_string(),
198→            "sandbox".to_string(),
199→            // Mask /sys subtrees that expose host hardware identifiers
200→            // (serial numbers, BIOS/UEFI data, disk models, LUKS UUIDs).
201→            // Empty read-only tmpfs overlays hide the underlying sysfs entries
202→            // and work identically on Docker and Podman.
203→            "--tmpfs".to_string(),
204→            "/sys/firmware:ro,nosuid".to_string(),
205→            "--tmpfs".to_string(),
206→            "/sys/class/dmi:ro,nosuid".to_string(),
207→            "--tmpfs".to_string(),
208→            "/sys/devices/virtual/dmi:ro,nosuid".to_string(),
209→            "--tmpfs".to_string(),
210→            "/sys/class/block:ro,nosuid".to_string(),
211→        ];
212→        if is_prebuilt {
213→            args.push("--read-only".to_string());
214→        }
215→        args
216→    }
217→
218→    pub(crate) fn workspace_args(&self) -> Vec<String> {
219→        let guest_workspace_dir = moltis_config::data_dir();
220→        let host_workspace_dir = host_visible_data_dir(&self.config, Some(self.cli));
221→        let guest_workspace_dir_str = guest_workspace_dir.display().to_string();
222→        let host_workspace_dir_str = host_workspace_dir.display().to_string();
223→        match self.config.workspace_mount {
224→            WorkspaceMount::Ro => vec![
225→                "-v".to_string(),
226→                format!("{host_workspace_dir_str}:{guest_workspace_dir_str}:ro"),
227→            ],
228→            WorkspaceMount::Rw => vec![
229→                "-v".to_string(),
230→                format!("{host_workspace_dir_str}:{guest_workspace_dir_str}:rw"),
231→            ],
232→            WorkspaceMount::None => Vec::new(),
233→        }
234→    }
235→
236→    pub(crate) fn home_persistence_args(&self, id: &SandboxId) -> Result<Vec<String>> {
237→        let Some(host_dir) =
238→            ensure_sandbox_home_persistence_host_dir(&self.config, Some(self.cli), id)?
239→        else {
240→            return Ok(Vec::new());
241→        };
242→        let volume = format!("{}:{SANDBOX_HOME_DIR}:rw", host_dir.display());
243→        Ok(vec!["-v".to_string(), volume])
244→    }
245→
246→    async fn resolve_local_image(&self, requested_image: &str) -> Result<String> {
247→        if sandbox_image_exists(self.cli, requested_image).await {
248→            return Ok(requested_image.to_string());
249→        }
250→
251→        let base_image = self.image().to_string();
252→        let packages = self.config.packages.clone();
253→        let Some(rebuild_tag) = rebuildable_sandbox_image_tag(
254→            requested_image,
255→            self.image_repo(),
256→            &base_image,
257→            &packages,
258→        ) else {
259→            return Ok(requested_image.to_string());
260→        };
261→
262→        if requested_image == rebuild_tag {
263→            info!(
264→                image = requested_image,
265→                "sandbox image missing locally, rebuilding on demand"
266→            );
267→        } else {
268→            warn!(
269→                requested = requested_image,
270→                rebuilt = %rebuild_tag,
271→                "requested sandbox image missing locally, using deterministic tag from current config"
272→            );
273→        }
274→
275→        let Some(result) = self.build_image(&base_image, &packages).await? else {
276→            return Ok(requested_image.to_string());
277→        };
278→        Ok(result.tag)
279→    }
280→}
281→
282→#[async_trait]
283→impl Sandbox for DockerSandbox {
284→    fn backend_name(&self) -> &'static str {
285→        self.backend_label
286→    }
287→
288→    async fn ensure_ready(&self, id: &SandboxId, image_override: Option<&str>) -> Result<()> {
289→        let name = self.container_name(id);
290→
291→        // Check if container already running.
292→        let check = tokio::process::Command::new(self.cli)
293→            .args(["inspect", "--format", "{{.State.Running}}", &name])
294→            .output()
295→            .await;
296→
297→        if let Ok(output) = check {
298→            let stdout = String::from_utf8_lossy(&output.stdout);
299→            if stdout.trim() == "true" {
300→                return Ok(());
301→            }
302→        }
303→
304→        // Resolve image first so we know whether it's prebuilt (affects hardening).
305→        let requested_image = image_override.unwrap_or_else(|| self.image());
306→        let image = self.resolve_local_image(requested_image).await?;
307→        let is_prebuilt = image.starts_with(&format!("{}:", self.image_repo()));
308→
309→        // Start a new container.
310→        let mut args = vec![
311→            "run".to_string(),
312→            "-d".to_string(),
313→            "--name".to_string(),
314→            name.clone(),
315→        ];
316→
317→        args.extend(self.network_run_args());
318→
319→        if let Some(ref tz) = self.config.timezone {
320→            args.extend(["-e".to_string(), format!("TZ={tz}")]);
321→        }
322→
323→        args.extend(self.resource_args());
324→        args.extend(Self::hardening_args(is_prebuilt));
325→        args.extend(self.workspace_args());
326→        args.extend(self.home_persistence_args(id)?);
327→
328→        args.push(image.clone());
329→        args.extend(["sleep".to_string(), "infinity".to_string()]);
330→
331→        let output = tokio::process::Command::new(self.cli)
332→            .args(&args)
333→            .output()
334→            .await?;
335→
336→        if !output.status.success() {
337→            let stderr = String::from_utf8_lossy(&output.stderr);
338→            return Err(Error::message(format!(
339→                "{} run failed: {}",
340→                self.cli,
341→                stderr.trim()
342→            )));
343→        }
344→
345→        // Skip provisioning if the image is a pre-built instance sandbox image
346→        // (packages are already baked in — including /home/sandbox from the Dockerfile).
347→        if !is_prebuilt {
348→            provision_packages(self.cli, &name, &self.config.packages).await?;
349→        }
350→
351→        Ok(())
352→    }
353→
354→    async fn build_image(
355→        &self,
356→        base: &str,
357→        packages: &[String],
358→    ) -> Result<Option<BuildImageResult>> {
359→        if packages.is_empty() {
360→            return Ok(None);
361→        }
362→
363→        let tag = sandbox_image_tag(self.image_repo(), base, packages);
364→
365→        // Check if image already exists.
366→        if sandbox_image_exists(self.cli, &tag).await {
367→            info!(
368→                tag,
369→                "pre-built sandbox image already exists, skipping build"
370→            );
371→            return Ok(Some(BuildImageResult { tag, built: false }));
372→        }
373→
374→        // Generate Dockerfile in a temp dir.
375→        let tmp_dir =
376→            std::env::temp_dir().join(format!("moltis-sandbox-build-{}", uuid::Uuid::new_v4()));
377→        std::fs::create_dir_all(&tmp_dir)?;
378→
379→        let pkg_list = canonical_sandbox_packages(packages).join(" ");
380→        let dockerfile = sandbox_image_dockerfile(base, packages);
381→        let dockerfile_path = tmp_dir.join("Dockerfile");
382→        std::fs::write(&dockerfile_path, &dockerfile)?;
383→
384→        info!(tag, packages = %pkg_list, "building pre-built sandbox image");
385→
386→        let output = tokio::process::Command::new(self.cli)
387→            .args(["build", "-t", &tag, "-f"])
388→            .arg(&dockerfile_path)
389→            .arg(&tmp_dir)
390→            .stdout(std::process::Stdio::piped())
391→            .stderr(std::process::Stdio::piped())
392→            .output()
393→            .await;
394→
395→        // Clean up temp dir regardless of result.
396→        let _ = std::fs::remove_dir_all(&tmp_dir);
397→
398→        let output = output?;
399→        if !output.status.success() {
400→            let stderr = String::from_utf8_lossy(&output.stderr);
401→            return Err(Error::message(format!(
402→                "{} build failed for {tag}: {}",
403→                self.cli,
404→                stderr.trim()
405→            )));
406→        }
407→
408→        info!(tag, "pre-built sandbox image ready");
409→        Ok(Some(BuildImageResult { tag, built: true }))
410→    }
411→
412→    async fn exec(&self, id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
413→        let name = self.container_name(id);
414→
415→        let mut args = vec!["exec".to_string()];
416→
417→        if let Some(ref dir) = opts.working_dir {
418→            args.extend(["-w".to_string(), dir.display().to_string()]);
419→        }
420→
421→        // Inject proxy env vars so traffic routes through the trusted-network
422→        // proxy running on the host.
423→        args.extend(self.proxy_exec_env_args());
424→
425→        for (k, v) in &opts.env {
426→            args.extend(["-e".to_string(), format!("{}={}", k, v)]);
427→        }
428→
429→        args.push(name);
430→        args.extend(["sh".to_string(), "-c".to_string(), command.to_string()]);
431→
432→        let child = tokio::process::Command::new(self.cli)
433→            .args(&args)
434→            .stdout(std::process::Stdio::piped())
435→            .stderr(std::process::Stdio::piped())
436→            .stdin(std::process::Stdio::null())
437→            .spawn()?;
438→
439→        let result = tokio::time::timeout(opts.timeout, child.wait_with_output()).await;
440→
441→        match result {
442→            Ok(Ok(output)) => {
443→                let mut stdout = String::from_utf8_lossy(&output.stdout).into_owned();
444→                let mut stderr = String::from_utf8_lossy(&output.stderr).into_owned();
445→
446→                truncate_output_for_display(&mut stdout, opts.max_output_bytes);
447→                truncate_output_for_display(&mut stderr, opts.max_output_bytes);
448→
449→                Ok(ExecResult {
450→                    stdout,
451→                    stderr,
452→                    exit_code: output.status.code().unwrap_or(-1),
453→                })
454→            },
455→            Ok(Err(e)) => {
456→                return Err(Error::message(format!("{} exec failed: {e}", self.cli)));
457→            },
458→            Err(_) => {
459→                return Err(Error::message(format!(
460→                    "{} exec timed out after {}s",
461→                    self.cli,
462→                    opts.timeout.as_secs()
463→                )));
464→            },
465→        }
466→    }
467→
468→    async fn read_file(
469→        &self,
470→        id: &SandboxId,
471→        file_path: &str,
472→        max_bytes: u64,
473→    ) -> Result<SandboxReadResult> {
474→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
475→            return native_host_read_file(
476→                host_path
477→                    .to_str()
478→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
479→                max_bytes,
480→            )
481→            .await;
482→        }
483→
484→        let container_name = self.container_name(id);
485→        oci_container_read_file(self.cli, &container_name, file_path, max_bytes).await
486→    }
487→
488→    async fn write_file(
489→        &self,
490→        id: &SandboxId,
491→        file_path: &str,
492→        content: &[u8],
493→    ) -> Result<Option<serde_json::Value>> {
494→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
495→            return native_host_write_file(
496→                host_path
497→                    .to_str()
498→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
499→                content,
500→            )
501→            .await;
502→        }
503→
504→        let container_name = self.container_name(id);
505→        oci_container_write_file(self.cli, &container_name, file_path, content).await
506→    }
507→
508→    async fn list_files(&self, id: &SandboxId, root: &str) -> Result<SandboxListFilesResult> {
509→        if let Some(host_path) = self.mounted_host_path(id, root) {
510→            let host_files = native_host_list_files(
511→                host_path
512→                    .to_str()
513→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
514→            )
515→            .await?;
516→            return remap_host_list_result_to_guest(root, &host_path, host_files);
517→        }
518→
519→        let container_name = self.container_name(id);
520→        oci_container_list_files(self.cli, &container_name, root).await
521→    }
522→
523→    async fn cleanup(&self, id: &SandboxId) -> Result<()> {
524→        let name = self.container_name(id);
525→        let _ = tokio::process::Command::new(self.cli)
526→            .args(["rm", "-f", &name])
527→            .output()
528→            .await;
529→        Ok(())
530→    }
531→}
