581→/// Return `true` when the installed Podman version supports `host-gateway`
582→/// in `--add-host` (added in Podman 5.0).
583→pub(crate) fn podman_supports_host_gateway() -> bool {
584→    let Ok(output) = std::process::Command::new("podman")
585→        .args(["version", "--format", "{{.Client.Version}}"])
586→        .output()
587→    else {
588→        return false;
589→    };
590→    let version_str = String::from_utf8_lossy(&output.stdout);
591→    let major: u32 = version_str
592→        .trim()
593→        .split('.')
594→        .next()
595→        .and_then(|s| s.parse().ok())
596→        .unwrap_or(0);
597→    major >= 5
598→}
599→
600→/// Resolve the host IP that a Podman container (< 5.0) can use to reach the
601→/// host.  Rootless Podman defaults to slirp4netns where the host is always
602→/// `10.0.2.2`.  Rootful Podman uses a bridge network whose gateway we query
603→/// with `podman network inspect`.
604→pub(crate) fn podman_resolve_host_ip() -> Option<String> {
605→    let rootless = std::process::Command::new("podman")
606→        .args(["info", "--format", "{{.Host.Security.Rootless}}"])
607→        .output()
608→        .ok()
609→        .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string());
610→
611→    if rootless.as_deref() == Some("true") {
